const query = $input.first().json.query;
const words = query.trim().split(/\s+/).filter(w => w.length > 0);

// AND together a "name contains word" condition for every word
const nameConditions = words.map(w => ["name", "ilike", w]);
const andOperators = Array(Math.max(0, nameConditions.length - 1)).fill("&");
const nameGroup = [...andOperators, ...nameConditions];

// OR: (all words in name)  OR  (full query matches SKU)  OR  (full query matches barcode)
const domain = [
  "|", "|",
  ...nameGroup,
  ["default_code", "ilike", query],
  ["barcode", "ilike", query]
];

return [{ json: { query, domain } }];

// Simple word-overlap similarity: fraction of query words found in the product name
function matchScore(query, name) {
  const queryWords = query.toLowerCase().trim().split(/\s+/);
  const nameLower = name.toLowerCase();
  const matched = queryWords.filter(w => nameLower.includes(w));
  return Math.round((matched.length / queryWords.length) * 100) / 100;
}

const query = $('build_search_domain').first().json.query;
const results = $input.first().json.result;

const ranked = results.map(product => ({
  product_id: product.id,
  name: product.name,
  default_code: product.default_code,
  match_score: matchScore(query, product.name)
})).sort((a, b) => b.match_score - a.match_score);

return [{ json: { query, matches: ranked } }];
